void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    ret = texture(sampler_main, vUv).xyz;
    ret = 1-ret;

    ret *= 1.14; //gamma
    ret *= ret; //darken

  fragColor = ret;
